@startuml
left to right direction
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class "Matrícula" {
  [C]
  -cliente: Client
  -tempo: Int
  -quadra: Turma
}

class "Aluno" {
  [C]
  -id: Int
  -nome: String
  -local: List<Matrícula>
}

class "controleNúmeroMatrícula" {
  [C]
  -quantidade: Int
}

class "Turma" {
  [C]
  -numero: Int
  -aluguel: Matrícula
  -ginasio: Curso
}

class "Curso" {
  [C]
  -nome: String
  -quadra: List<Turma>
}

"Matrícula" --|> "controleNúmeroMatrícula" : composição
"Matrícula" -- "Turma" : composição
"Turma" -- "Curso" : composição
"Aluno" -- "Matrícula" : composição

@enduml
